=Triage this inbound ArcVault message and return only the JSON schema output.

message_id: {{$('Normalize Input').item.json.message_id}}
source: {{$('Normalize Input').item.json.source}}
raw_message: {{$('Normalize Input').item.json.raw_message}}

parameters.jsCode:
const inputItems = $input.all();

// Original cleaned intake rows.
let originalItems = [];

try {
  originalItems = $('Filter Valid Rows').all();
} catch (error) {
  originalItems = $('Normalize Input').all().filter((item) => {
    const source = String(item.json.source ?? item.json.Source ?? '').trim();
    const rawMessage = String(
      item.json.raw_message ??
      item.json['Raw Message'] ??
      item.json.Message ??
      item.json.message ??
      ''
    ).trim();

    return source !== '' && rawMessage !== '';
  });
}

function clean(value, fallback = '') {
  return String(value ?? fallback).trim();
}

function extractTriagePayload(openAiJson) {
  const candidates = [
    openAiJson,
    openAiJson.output_text,
    openAiJson.response,
    openAiJson.text,
    openAiJson.message?.content,
    openAiJson.content?.[0]?.text,
    openAiJson.output?.[0]?.content?.[0]?.text,
    openAiJson.choices?.[0]?.message?.content,
  ];

  for (const candidate of candidates) {
    if (!candidate) continue;

    if (typeof candidate === 'object' && candidate !== null && candidate.category) {
      return candidate;
    }

    if (typeof candidate === 'string') {
      const cleaned = candidate
        .replace(/^```json\s*/i, '')
        .replace(/^```/i, '')
        .replace(/```$/i, '')
        .trim();

      try {
        const parsed = JSON.parse(cleaned);

        if (parsed && typeof parsed === 'object' && parsed.category) {
          return parsed;
        }
      } catch (error) {
        // Try the next candidate.
      }
    }
  }

  return null;
}

function normalizeIdentifiers(identifiers) {
  const empty = {
    account_id: 'nan',
    account_path: 'nan',
    invoice_number: 'nan',
    error_code: 'nan',
    url: 'nan',
    auth_provider: 'nan',
    product_area: 'nan',
    requested_feature: 'nan',
    reported_time: 'nan',
    contract_reference: 'nan',
    other_identifiers: 'nan',
  };

  if (!identifiers || typeof identifiers !== 'object' || Array.isArray(identifiers)) {
    return empty;
  }

  return {
    ...empty,
    ...identifiers,
  };
}

const queueMap = {
  'Bug Report': 'Engineering',
  'Feature Request': 'Product',
  'Billing Issue': 'Billing',
  'Technical Question': 'IT/Security',
  'Incident/Outage': 'Engineering',
};

const outageLanguage = [
  'outage',
  'down for all users',
  'multiple users affected',
  'stopped loading',
  'dashboard stopped loading',
];

const processedAt = new Date().toISOString();

if (inputItems.length === 0) {
  return [];
}

if (originalItems.length < inputItems.length) {
  throw new Error(
    `Mismatch: OpenAI returned ${inputItems.length} items, but only ${originalItems.length} valid original rows were found. Check Filter Valid Rows.`
  );
}

return inputItems.map((item, index) => {
  const originalByIndex = originalItems[index]?.json || {};

  const original = {
    source: clean(
      originalByIndex.source ??
      originalByIndex.Source,
      'Unknown'
    ),

    raw_message: clean(
      originalByIndex.raw_message ??
      originalByIndex['Raw Message'] ??
      originalByIndex.Message ??
      originalByIndex.message
    ),

    customer_email: clean(
      originalByIndex.customer_email ??
      originalByIndex['Customer Email'] ??
      originalByIndex.email
    ),

    // Timestamp from Google Form / Google Sheet
    timestamp: clean(
      originalByIndex.timestamp ??
      originalByIndex.Timestamp
    ),
  };

  const triage = extractTriagePayload(item.json);

  if (!triage) {
    throw new Error(`Could not find a structured triage payload in OpenAI output for item ${index + 1}.`);
  }

  if (!original.raw_message) {
    throw new Error(`Missing raw_message for item ${index + 1}. Check Normalize Input and Filter Valid Rows.`);
  }

  const confidenceScore = Number(triage.confidence_score);

  const actualAmount =
    triage.actual_amount === null || triage.actual_amount === ''
      ? null
      : Number(triage.actual_amount);

  const expectedAmount =
    triage.expected_amount === null || triage.expected_amount === ''
      ? null
      : Number(triage.expected_amount);

  const discrepancyAmount =
    triage.discrepancy_amount === null || triage.discrepancy_amount === ''
      ? null
      : Number(triage.discrepancy_amount);

  const rawMessageLower = original.raw_message.toLowerCase();

  const escalationReasons = [];

  if (confidenceScore < 0.7) {
    escalationReasons.push('confidence_below_0_70');
  }

  if (triage.category === 'Incident/Outage') {
    escalationReasons.push('incident_outage_category');
  }

  if (triage.affected_scope === 'multiple_users') {
    escalationReasons.push('multiple_users_affected');
  }

  if (outageLanguage.some((phrase) => rawMessageLower.includes(phrase))) {
    escalationReasons.push('outage_language_detected');
  }

  if (typeof discrepancyAmount === 'number' && discrepancyAmount > 500) {
    escalationReasons.push('billing_discrepancy_above_500');
  }

  const standardQueue = queueMap[triage.category] || 'Human Review';
  const escalationFlag = escalationReasons.length > 0;
  const destinationQueue = escalationFlag ? 'Human Review' : standardQueue;

  return {
    json: {
      source: original.source,
      raw_message: original.raw_message,
      customer_email: original.customer_email,
      timestamp: original.timestamp,

      category: triage.category,
      priority: triage.priority,
      confidence_score: confidenceScore,

      core_issue: triage.core_issue,
      identifiers: normalizeIdentifiers(triage.identifiers),

      urgency_signal: triage.urgency_signal,
      affected_scope: triage.affected_scope || 'unknown',

      actual_amount: actualAmount,
      expected_amount: expectedAmount,
      discrepancy_amount: discrepancyAmount,

      standard_queue: standardQueue,
      destination_queue: destinationQueue,
      escalation_flag: escalationFlag,
      escalation_reason: escalationReasons.length ? escalationReasons.join(', ') : null,

      summary: triage.summary,

      received_at: processedAt,
      processed_at: processedAt,
    },
  };
});
